<?php
namespace App\Http\Controllers;
use App\Models\User; use Illuminate\Http\RedirectResponse; use Illuminate\Http\Request; use Illuminate\Support\Facades\Artisan; use Illuminate\Support\Facades\DB; use Illuminate\Support\Facades\File; use Illuminate\View\View; use PDO; use Throwable;
class InstallController extends Controller {
 public function create(): View { $requirements=['PHP 8.2+'=>version_compare(PHP_VERSION,'8.2.0','>='),'PDO MySQL'=>extension_loaded('pdo_mysql'),'OpenSSL'=>extension_loaded('openssl'),'Mbstring'=>extension_loaded('mbstring'),'CURL'=>extension_loaded('curl'),'Writable storage'=>is_writable(storage_path())]; return view('install',compact('requirements')); }
 public function store(Request $request): RedirectResponse { $data=$request->validate(['app_name'=>['required','string','max:80'],'app_url'=>['required','url','max:255'],'db_host'=>['required','string','max:190'],'db_port'=>['required','integer','between:1,65535'],'db_database'=>['required','string','max:64'],'db_username'=>['required','string','max:64'],'db_password'=>['nullable','string','max:255'],'owner_name'=>['required','string','max:100'],'owner_email'=>['required','email','max:190'],'owner_password'=>['required','string','min:12','confirmed']]); try { new PDO("mysql:host={$data['db_host']};port={$data['db_port']};dbname={$data['db_database']};charset=utf8mb4",$data['db_username'],$data['db_password']??'',[PDO::ATTR_ERRMODE=>PDO::ERRMODE_EXCEPTION]); $key='base64:'.base64_encode(random_bytes(32)); $this->writeEnvironment($data,$key); config(['app.key'=>$key,'database.default'=>'mysql','database.connections.mysql.host'=>$data['db_host'],'database.connections.mysql.port'=>$data['db_port'],'database.connections.mysql.database'=>$data['db_database'],'database.connections.mysql.username'=>$data['db_username'],'database.connections.mysql.password'=>$data['db_password']??'']); DB::purge('mysql'); DB::reconnect('mysql'); Artisan::call('migrate',['--force'=>true]); User::create(['name'=>$data['owner_name'],'email'=>strtolower($data['owner_email']),'password'=>$data['owner_password'],'role'=>'owner','locale'=>'bg']); File::put(storage_path('app/nexus-installed'),now()->toIso8601String()); Artisan::call('optimize:clear'); } catch(Throwable $e) { report($e); return back()->withInput($request->except(['db_password','owner_password','owner_password_confirmation']))->withErrors(['install'=>'Инсталацията не завърши: '.$e->getMessage()]); } return redirect()->route('login')->with('success','NEXUS е инсталиран успешно.'); }
 private function writeEnvironment(array $data,string $key): void { $q=fn(string $v):string=>'"'.str_replace(['\\','"'],['\\\\','\\"'],$v).'"'; $env="APP_NAME={$q($data['app_name'])}\nAPP_ENV=production\nAPP_KEY={$key}\nAPP_DEBUG=false\nAPP_URL={$q(rtrim($data['app_url'],'/'))}\nAPP_LOCALE=bg\nAPP_FALLBACK_LOCALE=en\nLOG_CHANNEL=daily\nLOG_LEVEL=warning\nDB_CONNECTION=mysql\nDB_HOST={$q($data['db_host'])}\nDB_PORT={$data['db_port']}\nDB_DATABASE={$q($data['db_database'])}\nDB_USERNAME={$q($data['db_username'])}\nDB_PASSWORD={$q($data['db_password']??'')}\nSESSION_DRIVER=file\nSESSION_SECURE_COOKIE=true\nCACHE_STORE=file\nQUEUE_CONNECTION=database\n"; if(File::put(base_path('.env'),$env,true)===false) throw new \RuntimeException('Не може да бъде записан .env.'); }
}
